const fs = require('fs');
const path = require('path');

const vaultPath = '/home/zacmero/Documents/mero-vault';
const indexPath = path.join(vaultPath, 'vault_index.json');

function findMarkdownFiles(dir, fileList = []) {
    const files = fs.readdirSync(dir);
    for (const file of files) {
        const filePath = path.join(dir, file);
        if (fs.statSync(filePath).isDirectory()) {
            if (!filePath.includes('.obsidian') && !filePath.includes('.smart-env') && !filePath.includes('.trash') && !filePath.includes('.git')) {
                findMarkdownFiles(filePath, fileList);
            }
        } else if (file.endsWith('.md') && file !== 'vault_index.json') {
            fileList.push(filePath);
        }
    }
    return fileList;
}

const mdFiles = findMarkdownFiles(vaultPath);
const indexData = [];

for (const file of mdFiles) {
    const content = fs.readFileSync(file, 'utf8');
    const relativePath = path.relative(vaultPath, file);

    let tags = [];
    let summary = "";

    // Naive frontmatter parsing
    const fmMatch = content.match(/^---\n([\s\S]*?)\n---/);
    if (fmMatch) {
        const fm = fmMatch[1];

        // Match tags: [...] or tags: \n  - ...
        const tagsMatch = fm.match(/tags:\s*\[(.*?)\]/);
        if (tagsMatch) {
            tags = tagsMatch[1].split(',').map(t => t.trim().replace(/['"]/g, ''));
        } else {
            const tagsListMatch = fm.match(/tags:([\s\S]*?)(?=\n[a-z]+:|$)/);
            if (tagsListMatch) {
                tags = tagsListMatch[1].split('\n')
                    .filter(l => l.trim().startsWith('-'))
                    .map(l => l.trim().substring(1).trim());
            }
        }

        // Match summary or description
        const sumMatch = fm.match(/summary:\s*(.*)/) || fm.match(/description:\s*(.*)/);
        if (sumMatch) {
            summary = sumMatch[1].replace(/['"]/g, '').trim();
        }
    }

    // Also look for inline tags like #tag
    const inlineTags = [...content.matchAll(/(?<=\s|^)#([a-zA-Z0-9_-]+)/g)].map(m => m[1]);
    tags = [...new Set([...tags, ...inlineTags])];

    indexData.push({
        title: path.basename(file, '.md'),
        path: relativePath,
        tags: tags,
        summary: summary
    });
}

fs.writeFileSync(indexPath, JSON.stringify(indexData, null, 2));
console.log(`Indexed ${indexData.length} files to ${indexPath}`);

